273	func captureStdout(fn func() error) (string, error) {
274		old := os.Stdout
275		r, w, err := os.Pipe()
276		if err != nil {
277			return "", err
278		}
279		os.Stdout = w
280		defer func() { os.Stdout = old }()
281	
282		runErr := fn()
283		_ = w.Close()
284	
285		var buf bytes.Buffer
286		if _, err := io.Copy(&buf, r); err != nil {
287			return "", err
288		}
289		_ = r.Close()
290		return strings.TrimSpace(buf.String()), runErr
291	}
