305	func makeCommits(t *testing.T, repo *git.Repository, fs billy.Filesystem, count int) {
306		t.Helper()
307	
308		wt, err := repo.Worktree()
309		if err != nil {
310			t.Fatalf("open worktree: %v", err)
311		}
312	
313		for i := range count {
314			content := strings.Repeat(fmt.Sprintf("line %d %d\n", i, time.Now().UnixNano()), 24)
315			file, err := fs.Create("tracked.txt")
316			if err != nil {
317				t.Fatalf("create file: %v", err)
318			}
319			if _, err := io.WriteString(file, content); err != nil {
