326			if _, err := wt.Add("tracked.txt"); err != nil {
327				t.Fatalf("add file: %v", err)
328			}
329	
330			_, err = wt.Commit(fmt.Sprintf("commit %d", i), &git.CommitOptions{
331				Author:    &objectSignature,
332				Committer: &objectSignature,
333			})
334			if err != nil {
