350	type smartHTTPRepoServer struct {
351		t        *testing.T
352		server   *httptest.Server
353		repo     *git.Repository
354		repoPath string
355	
356		mu           sync.Mutex
357		receivePacks int
358		thinCapable  bool
359	}
360	
361	func newSmartHTTPRepoServer(t *testing.T, repo *git.Repository) *smartHTTPRepoServer {
362		t.Helper()
363	
364		s := &smartHTTPRepoServer{
365			t:           t,
366			repo:        repo,
367			repoPath:    "/repo.git",
368			thinCapable: true,
369		}
370		s.server = httptest.NewServer(http.HandlerFunc(s.handle))
371		return s
372	}
373	
374	func (s *smartHTTPRepoServer) Close() {
375		s.server.Close()
376	}
377	
378	func (s *smartHTTPRepoServer) RepoURL() string {
379		return s.server.URL + s.repoPath
380	}
381	
382	func (s *smartHTTPRepoServer) Count(service string) int {
383		s.mu.Lock()
384		defer s.mu.Unlock()
385		if service == "git-receive-pack" {
386			return s.receivePacks
387		}
388		return 0
389	}
390	
391	func (s *smartHTTPRepoServer) handle(w http.ResponseWriter, r *http.Request) {
392		switch {
393		case r.Method == http.MethodGet && r.URL.Path == s.repoPath+"/info/refs":
394			s.handleInfoRefs(w, r)
395		case r.Method == http.MethodPost && r.URL.Path == s.repoPath+"/git-upload-pack":
396			s.handleUploadPack(w, r)
397		case r.Method == http.MethodPost && r.URL.Path == s.repoPath+"/git-receive-pack":
398			s.handleReceivePack(w, r)
399		default:
400			http.NotFound(w, r)
401		}
402	}
403	
404	func (s *smartHTTPRepoServer) handleInfoRefs(w http.ResponseWriter, r *http.Request) {
405		service := transport.Service(r.URL.Query().Get("service"))
406		if service != transport.UploadPackService && service != transport.ReceivePackService {
407			http.Error(w, "missing service", http.StatusBadRequest)
408			return
409		}
410	
411		var buf bytes.Buffer
412		if err := transport.AdvertiseReferences(r.Context(), s.repo.Storer, &buf, service, false); err != nil {
413			http.Error(w, err.Error(), http.StatusInternalServerError)
414			return
415		}
416		if service == transport.ReceivePackService && s.thinCapable {
417			rewritten, err := rewriteReceivePackAdvertisement(buf.Bytes(), func(caps *capability.List) {
418				caps.Delete(capability.Capability("no-thin"))
419			})
420			if err != nil {
421				s.t.Fatalf("rewrite receive-pack advertisement: %v", err)
422			}
423			buf.Reset()
424			_, _ = buf.Write(rewritten)
425		}
426	
427		w.Header().Set("Content-Type", fmt.Sprintf("application/x-%s-advertisement", service))
428		if _, err := w.Write(buf.Bytes()); err != nil {
429			s.t.Fatalf("write advertised refs: %v", err)
430		}
431	}
432	
433	func rewriteReceivePackAdvertisement(data []byte, mutate func(*capability.List)) ([]byte, error) {
434		ar := packp.NewAdvRefs()
435		if err := ar.Decode(bytes.NewReader(data)); err == nil {
436			mutate(ar.Capabilities)
437			var buf bytes.Buffer
438			if err := ar.Encode(&buf); err != nil {
439				return nil, err
440			}
441			return buf.Bytes(), nil
442		}
443	
444		rd := bytes.NewReader(data)
445		var smart packp.SmartReply
446		if err := smart.Decode(rd); err != nil {
447			return nil, err
448		}
449		ar = packp.NewAdvRefs()
450		if err := ar.Decode(rd); err != nil {
451			return nil, err
452		}
453		mutate(ar.Capabilities)
454		var buf bytes.Buffer
455		if err := smart.Encode(&buf); err != nil {
456			return nil, err
457		}
458		if err := ar.Encode(&buf); err != nil {
459			return nil, err
460		}
461		return buf.Bytes(), nil
462	}
463	
464	func (s *smartHTTPRepoServer) handleUploadPack(w http.ResponseWriter, r *http.Request) {
465		var buf bytes.Buffer
466		wc := nopWriteCloser{&buf}
467	
468		err := transport.UploadPack(r.Context(), s.repo.Storer, r.Body, wc, &transport.UploadPackOptions{
469			StatelessRPC: true,
470		})
471		if err != nil {
